mapper.select:
select * from orders


        and number like concat('%',#{number},'%')


        and phone like concat('%',#{phone},'%')


        and user_id = #{userId}


        and status = #{status}


        and status in

            #{item}



        and order_time >= #{beginTime}


        and order_time <= #{endTime}


        and volunteer_id = #{volunteerId}


        and dining_point_id = #{diningPointId}


        and elder_id = #{elderId}


        and volunteer_id is null


order by order_time desc

select sum(amount) from orders


        and status = #{status}


        and status in

            #{item}



        and order_time >= #{begin}


        and order_time <= #{end}


        and user_id = #{userId}


        and volunteer_id = #{volunteerId}


        and dining_point_id = #{diningPointId}


        and volunteer_id is null

select count(id) from orders


        and status = #{status}


        and status in

            #{item}



        and order_time >= #{begin}


        and order_time <= #{end}


        and user_id = #{userId}


        and volunteer_id = #{volunteerId}


        and dining_point_id = #{diningPointId}


        and volunteer_id is null

select count(1)
from orders
where elder_id = #{elderId}

select od.name name,sum(od.number) number from order_detail od ,orders o where od.order_id = o.id and o.status = 5
and order_time >= #{begin}
and order_time <= #{end}
group by name order by number desc limit 0, 10
